const webhookData = $input.first().json.body || $input.first().json;

const SKIP_LABELS = new Set([
  "alertname", "endpoint", "instance", "job",
  "metrics_path", "prometheus", "project", "env",
]);

const LABEL_RENAME = {
  "grafana_board": "Grafana Dashboard",
  "persistentvolumeclaim": "PVC",
};

const alerts = webhookData.alerts || [];
const results = [];

for (const alert of alerts) {
  const status = alert.status || "unknown";
  const labels = alert.labels || {};
  const annotations = alert.annotations || {};
  const alertname = labels.alertname || "UnknownAlert";
  const fingerprint = alert.fingerprint || "";
  const startsAt = alert.startsAt || "";
  const generatorURL = alert.generatorURL || "";

  const lines = [
    `Analyze this ${status.toUpperCase()} alert.`,
    `Alertname: ${alertname}`,
    `Severity: ${labels.severity || "unknown"}`,
  ];

  for (const key of Object.keys(labels).sort()) {
    if (SKIP_LABELS.has(key) || key === "severity") continue;
    const displayKey = LABEL_RENAME[key] || key;
    lines.push(`${displayKey}: ${labels[key]}`);
  }

  if (startsAt) lines.push(`Started At: ${startsAt}`);
  if (generatorURL) lines.push(`Alert Source: ${generatorURL}`);

  for (const key of Object.keys(annotations).sort()) {
    const displayKey = key.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase());
    lines.push(`${displayKey}: ${annotations[key]}`);
  }

  const chatInput = lines.join("\n");
  const sessionId = fingerprint
    ? `alert-${fingerprint}`
    : `alert-${alertname}-${labels.namespace || ""}-${labels.service || ""}`;

  results.push({
    json: {
      action: "sendMessage",
      chatInput,
      sessionId,
      alert_id: fingerprint,
      alertname,
    },
  });
}

return results;

let agentOutput = "";
let chatInput = "";
try {
  const agentData = $('AI Agent').first().json;
  agentOutput = agentData.output || "";
  chatInput = agentData.chatInput || "";
} catch (e) {
  // AI Agent node not executed in this run
}

// Get Mattermost posts from GetAlertMessages (direct input)
const postsData = $input.first().json;
const order = postsData.order || [];
const posts = postsData.posts || {};

// Extract alertname from chatInput
let alertname = "";
for (const line of chatInput.split("\n")) {
  if (line.startsWith("Alertname:")) {
    alertname = line.split(":").slice(1).join(":").trim();
    break;
  }
}

// Search for existing Alertmanager post with this alertname
let thread_root_id = "";

for (const postId of order) {
  const post = posts[postId] || {};
  const props = post.props || {};
  const attachments = props.attachments || [];

  for (const att of attachments) {
    const title = att.title || "";
    // Match alertname in attachment title, e.g. "[FIRING:1] KubeJobFailed"
    if (alertname && title.includes(alertname)) {
      thread_root_id = post.root_id || postId;
      break;
    }
  }
  if (thread_root_id) break;
}

return [{
  json: {
    thread_root_id,
    message: agentOutput,
    alertname,
  }
}];

const DEDUP_WINDOW_MS = 48 * 60 * 60 * 1000; // 48 hours
const now = Date.now();

const staticData = $getWorkflowStaticData('global');

if (!staticData.alertDedup) {
  staticData.alertDedup = {};
}

// Cleanup entries older than dedup window
for (const key of Object.keys(staticData.alertDedup)) {
  if (now - staticData.alertDedup[key] > DEDUP_WINDOW_MS) {
    delete staticData.alertDedup[key];
  }
}

// Build dedup key from alert labels
const chatInput = $input.first().json.chatInput || "";

const extractLabel = (label) => {
  const re = new RegExp(`(?:^|\\n)${label}:\\s*(.+)`, "i");
  const m = chatInput.match(re);
  return m ? m[1].trim() : "";
};

const dedupKey = [
  extractLabel("Alertname"),
  extractLabel("namespace"),
  extractLabel("service"),
  extractLabel("severity"),
  extractLabel("container"),
].join("|").toLowerCase();

// Check if already seen
if (staticData.alertDedup[dedupKey]) {
  const minutesAgo = Math.round((now - staticData.alertDedup[dedupKey]) / 60000);
  console.log(`[Dedup] SKIP: "${dedupKey}" seen ${minutesAgo}m ago`);
  return [];
}

// New alert — register and pass through
staticData.alertDedup[dedupKey] = now;
console.log(`[Dedup] PASS: "${dedupKey}" — store size: ${Object.keys(staticData.alertDedup).length}`);

return [$input.first()];

const rulesResponse = $input.first().json;

// Get original alert data preserved from DeduplicateAlerts
const alertData = $('DeduplicateAlerts').first().json;
const alertname = alertData.alertname || "";

let triggerQuery = "";
let triggerDuration = "";

try {
  const groups = rulesResponse?.data?.groups || [];
  for (const group of groups) {
    const rules = group.rules || [];
    for (const rule of rules) {
      // Match by name (should already be filtered by rule_name[] param, but double-check)
      if (rule.name === alertname || rule.name === alertData.alertname) {
        triggerQuery = rule.query || "";
        // Duration in seconds (the 'for' clause)
        if (rule.duration) {
          triggerDuration = `${rule.duration}s`;
        }
        break;
      }
    }
    if (triggerQuery) break;
  }
} catch (e) {
  console.log(`[ExtractRuleQuery] Error parsing rules response: ${e.message}`);
}

// Build the enriched chatInput with trigger condition
let chatInput = alertData.chatInput || "";

if (triggerQuery) {
  chatInput += `\nTrigger Query (PromQL): ${triggerQuery}`;
  if (triggerDuration) {
    chatInput += `\nTrigger Duration (for): ${triggerDuration}`;
  }
} else {
  console.log(`[ExtractRuleQuery] No rule found for alertname: "${alertname}"`);
}

return [{
  json: {
    ...alertData,
    chatInput,
    triggerQuery,
    triggerDuration,
  }
}];
